// src/App.js

import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { ToastContainer } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';
import './App.css';

// Context Providers
import { AuthProvider, useAuth } from './context/AuthContext';
import { WarehouseProvider } from './context/WarehouseContext';
import { NotificationProvider } from './context/NotificationContext';
import { SettingsProvider } from './context/SettingsContext';
import { PermissionProvider } from './context/PermissionContext';

// Components
import Header from './components/common/Header';
import Sidebar from './components/common/Sidebar';
import Footer from './components/common/Footer';
import Loading from './components/common/Loading';
import ProtectedRoute from './components/auth/ProtectedRoute';

// Auth Pages
import Login from './pages/Auth/Login';
import ForgotPassword from './pages/Auth/ForgotPassword';
import ChangePassword from './pages/Auth/ChangePassword';

// Main Pages
import Dashboard from './pages/Dashboard/Dashboard';

// Module 1: Nhập Hàng
import NhapHang from './pages/NhapHang/NhapHang';

// Module 2: Tạo Đơn
import TaoDon from './pages/TaoDon/TaoDon';
import QuanLyCuaHang from './pages/TaoDon/QuanLyCuaHang';
import QuanLySanPham from './pages/TaoDon/QuanLySanPham';

// Module 3: Xuất Hàng
import XuatHang from './pages/XuatHang/XuatHang';

// Module 4: Quản Lý Kho
import QuanLyKho from './pages/QuanLyKho/QuanLyKho';
import QuanLyViTri from './pages/QuanLyKho/QuanLyViTri';
import QuanLyHangHoa from './pages/QuanLyKho/QuanLyHangHoa';
import TinhTrangHang from './pages/QuanLyKho/TinhTrangHang';
import KiemKe from './pages/QuanLyKho/KiemKe';
import BaoTri from './pages/QuanLyKho/BaoTri';

// Module 5: Kiểm Tra Giao Hàng
import KiemTraGiaoHang from './pages/KiemTraGiaoHang/KiemTraGiaoHang';

// Reports & Analytics
import BaoCao from './pages/BaoCao/BaoCao';

// Settings & Admin
import Settings from './pages/Settings/Settings';
import AdminDashboard from './pages/Admin/AdminDashboard';
import UserManagement from './pages/Admin/UserManagement';
import RoleManagement from './pages/Admin/RoleManagement';

// Error Pages
import NotFound from './pages/Error/NotFound';
import Unauthorized from './pages/Error/Unauthorized';

// Services
import { checkSystemHealth } from './services/api';

// Layout Component
const AppLayout = ({ children }) => {
  const { user } = useAuth();
  const [sidebarCollapsed, setSidebarCollapsed] = useState(false);
  const [systemHealth, setSystemHealth] = useState(null);

  useEffect(() => {
    // Check system health on app load
    const checkHealth = async () => {
      try {
        const health = await checkSystemHealth();
        setSystemHealth(health);
      } catch (error) {
        console.error('System health check failed:', error);
        setSystemHealth({ status: 'error', message: 'System unhealthy' });
      }
    };

    if (user) {
      checkHealth();
      // Check health every 5 minutes
      const interval = setInterval(checkHealth, 5 * 60 * 1000);
      return () => clearInterval(interval);
    }
  }, [user]);

  return (
    <div className={`app-layout ${sidebarCollapsed ? 'sidebar-collapsed' : ''}`}>
      {/* System Health Banner */}
      {systemHealth?.status === 'error' && (
        <div className="system-health-banner error">
          <i className="icon-alert-triangle"></i>
          <span>Hệ thống đang gặp sự cố: {systemHealth.message}</span>
        </div>
      )}

      {/* Header */}
      <Header 
        onToggleSidebar={() => setSidebarCollapsed(!sidebarCollapsed)}
        systemHealth={systemHealth}
      />

      {/* Main Content */}
      <div className="app-content">
        {/* Sidebar */}
        <Sidebar collapsed={sidebarCollapsed} />

        {/* Page Content */}
        <main className="main-content">
          <div className="content-wrapper">
            {children}
          </div>

          {/* Footer */}
          <Footer />
        </main>
      </div>
    </div>
  );
};

// Main App Component
const App = () => {
  const [appLoading, setAppLoading] = useState(true);
  const [appError, setAppError] = useState(null);

  useEffect(() => {
    // Initialize app
    const initializeApp = async () => {
      try {
        // Load app configuration
        await new Promise(resolve => setTimeout(resolve, 1000)); // Simulate loading
        setAppLoading(false);
      } catch (error) {
        console.error('App initialization failed:', error);
        setAppError(error.message);
        setAppLoading(false);
      }
    };

    initializeApp();
  }, []);

  if (appLoading) {
    return (
      <div className="app-loading">
        <Loading size="large" />
        <h2>Đang khởi tạo hệ thống...</h2>
        <p>Vui lòng đợi trong giây lát</p>
      </div>
    );
  }

  if (appError) {
    return (
      <div className="app-error">
        <i className="icon-alert-circle"></i>
        <h2>Không thể khởi tạo ứng dụng</h2>
        <p>{appError}</p>
        <button onClick={() => window.location.reload()}>
          Thử lại
        </button>
      </div>
    );
  }

  return (
    <AuthProvider>
      <PermissionProvider>
        <SettingsProvider>
          <WarehouseProvider>
            <NotificationProvider>
              <Router>
                <div className="App">
                  <Routes>
                    {/* Public Routes */}
                    <Route path="/login" element={<PublicRoute><Login /></PublicRoute>} />
                    <Route path="/forgot-password" element={<PublicRoute><ForgotPassword /></PublicRoute>} />

                    {/* Protected Routes */}
                    <Route path="/" element={
                      <ProtectedRoute>
                        <AppLayout>
                          <Navigate to="/dashboard" replace />
                        </AppLayout>
                      </ProtectedRoute>
                    } />

                    <Route path="/dashboard" element={
                      <ProtectedRoute>
                        <AppLayout>
                          <Dashboard />
                        </AppLayout>
                      </ProtectedRoute>
                    } />

                    {/* Module 1: Nhập Hàng */}
                    <Route path="/nhap-hang/*" element={
                      <ProtectedRoute module="nhap_hang" action="view">
                        <AppLayout>
                          <NhapHang />
                        </AppLayout>
                      </ProtectedRoute>
                    } />

                    {/* Module 2: Tạo Đơn */}
                    <Route path="/tao-don/*" element={
                      <ProtectedRoute module="tao_don" action="view">
                        <AppLayout>
                          <TaoDon />
                        </AppLayout>
                      </ProtectedRoute>
                    } />

                    <Route path="/quan-ly-cua-hang" element={
                      <ProtectedRoute module="tao_don" action="view">
                        <AppLayout>
                          <QuanLyCuaHang />
                        </AppLayout>
                      </ProtectedRoute>
                    } />

                    <Route path="/quan-ly-san-pham" element={
                      <ProtectedRoute module="tao_don" action="view">
                        <AppLayout>
                          <QuanLySanPham />
                        </AppLayout>
                      </ProtectedRoute>
                    } />

                    {/* Module 3: Xuất Hàng */}
                    <Route path="/xuat-hang/*" element={
                      <ProtectedRoute module="xuat_hang" action="view">
                        <AppLayout>
                          <XuatHang />
                        </AppLayout>
                      </ProtectedRoute>
                    } />

                    {/* Module 4: Quản Lý Kho */}
                    <Route path="/quan-ly-kho/*" element={
                      <ProtectedRoute module="quan_ly_kho" action="view">
                        <AppLayout>
                          <QuanLyKho />
                        </AppLayout>
                      </ProtectedRoute>
                    } />

                    <Route path="/quan-ly-vi-tri" element={
                      <ProtectedRoute module="quan_ly_kho" action="view">
                        <AppLayout>
                          <QuanLyViTri />
                        </AppLayout>
                      </ProtectedRoute>
                    } />

                    <Route path="/quan-ly-hang-hoa" element={
                      <ProtectedRoute module="quan_ly_kho" action="view">
                        <AppLayout>
                          <QuanLyHangHoa />
                        </AppLayout>
                      </ProtectedRoute>
                    } />

                    <Route path="/tinh-trang-hang" element={
                      <ProtectedRoute module="quan_ly_kho" action="view">
                        <AppLayout>
                          <TinhTrangHang />
                        </AppLayout>
                      </ProtectedRoute>
                    } />

                    <Route path="/kiem-ke" element={
                      <ProtectedRoute module="quan_ly_kho" action="view">
                        <AppLayout>
                          <KiemKe />
                        </AppLayout>
                      </ProtectedRoute>
                    } />

                    <Route path="/bao-tri" element={
                      <ProtectedRoute module="quan_ly_kho" action="view">
                        <AppLayout>
                          <BaoTri />
                        </AppLayout>
                      </ProtectedRoute>
                    } />

                    {/* Module 5: Kiểm Tra Giao Hàng */}
                    <Route path="/kiem-tra-giao-hang/*" element={
                      <ProtectedRoute module="kiem_tra_giao_hang" action="view">
                        <AppLayout>
                          <KiemTraGiaoHang />
                        </AppLayout>
                      </ProtectedRoute>
                    } />

                    {/* Reports */}
                    <Route path="/bao-cao/*" element={
                      <ProtectedRoute module="bao_cao" action="view">
                        <AppLayout>
                          <BaoCao />
                        </AppLayout>
                      </ProtectedRoute>
                    } />

                    {/* Settings */}
                    <Route path="/settings/*" element={
                      <ProtectedRoute>
                        <AppLayout>
                          <Settings />
                        </AppLayout>
                      </ProtectedRoute>
                    } />

                    <Route path="/change-password" element={
                      <ProtectedRoute>
                        <AppLayout>
                          <ChangePassword />
                        </AppLayout>
                      </ProtectedRoute>
                    } />

                    {/* Admin Routes */}
                    <Route path="/admin/*" element={
                      <ProtectedRoute module="admin" action="view">
                        <AppLayout>
                          <AdminDashboard />
                        </AppLayout>
                      </ProtectedRoute>
                    } />

                    <Route path="/admin/users" element={
                      <ProtectedRoute module="admin" action="view">
                        <AppLayout>
                          <UserManagement />
                        </AppLayout>
                      </ProtectedRoute>
                    } />

                    <Route path="/admin/roles" element={
                      <ProtectedRoute module="admin" action="view">
                        <AppLayout>
                          <RoleManagement />
                        </AppLayout>
                      </ProtectedRoute>
                    } />

                    {/* Error Routes */}
                    <Route path="/unauthorized" element={<Unauthorized />} />
                    <Route path="*" element={<NotFound />} />
                  </Routes>

                  {/* Toast Notifications */}
                  <ToastContainer
                    position="top-right"
                    autoClose={3000}
                    hideProgressBar={false}
                    newestOnTop={false}
                    closeOnClick
                    rtl={false}
                    pauseOnFocusLoss
                    draggable
                    pauseOnHover
                    theme="light"
                  />
                </div>
              </Router>
            </NotificationProvider>
          </WarehouseProvider>
        </SettingsProvider>
      </PermissionProvider>
    </AuthProvider>
  );
};

// Public Route Component (redirect to dashboard if already logged in)
const PublicRoute = ({ children }) => {
  const { user, loading } = useAuth();

  if (loading) {
    return <Loading />;
  }

  if (user) {
    return <Navigate to="/dashboard" replace />;
  }

  return children;
};

export default App;
